import{_ as e,o as a,c as n,a2 as t}from"./chunks/framework.CuteRReP.js";const u=JSON.parse('{"title":"TRIZ-Parallel: Safe Parallel Execution Engine","description":"","frontmatter":{},"headers":[],"relativePath":"triz-parallel.md","filePath":"triz-parallel.md"}'),i={name:"triz-parallel.md"};function l(r,s,o,p,c,h){return a(),n("div",null,[...s[0]||(s[0]=[t(`<h1 id="triz-parallel-safe-parallel-execution-engine" tabindex="-1">TRIZ-Parallel: Safe Parallel Execution Engine <a class="header-anchor" href="#triz-parallel-safe-parallel-execution-engine" aria-label="Permalink to &quot;TRIZ-Parallel: Safe Parallel Execution Engine&quot;">​</a></h1><blockquote><p><strong>3-5x Faster. Zero Merge Conflicts. Zero Hidden Bugs.</strong> Applies 6 TRIZ inventive principles to systematically resolve the Speed ↔ Quality contradiction in AI coding.</p></blockquote><h2 id="the-industry-problem" tabindex="-1">The Industry Problem <a class="header-anchor" href="#the-industry-problem" aria-label="Permalink to &quot;The Industry Problem&quot;">​</a></h2><p>According to 2025-2026 research, parallel AI coding delivers raw speed but causes systemic harm:</p><table tabindex="0"><thead><tr><th>Metric</th><th>Consequence</th></tr></thead><tbody><tr><td>+91% PR review time</td><td>More code generated, but human reviewers become the bottleneck</td></tr><tr><td>+18% static analysis warnings</td><td>Technical debt accumulates silently per session</td></tr><tr><td>45% of AI code has vulnerabilities</td><td>Security is sacrificed for speed</td></tr><tr><td>61% of devs say AI code &quot;looks correct but isn&#39;t&quot;</td><td>Hidden bugs that bypass initial scrutiny</td></tr></tbody></table><p><strong>The Core Contradiction:</strong> Developers want SPEED (parallel execution) but demand RELIABILITY (quality). Modern orchestrators force a trade-off.</p><h2 id="the-solution-6-triz-principles" tabindex="-1">The Solution: 6 TRIZ Principles <a class="header-anchor" href="#the-solution-6-triz-principles" aria-label="Permalink to &quot;The Solution: 6 TRIZ Principles&quot;">​</a></h2><p>TRIZ (Theory of Inventive Problem Solving) analyzed 2.5 million patents to codify universal problem-solving principles. CodyMaster applies 6 of these principles to parallel coding:</p><h3 id="_1-—-segmentation" tabindex="-1">#1 — Segmentation <a class="header-anchor" href="#_1-—-segmentation" aria-label="Permalink to &quot;#1 — Segmentation&quot;">​</a></h3><p><strong>Principle:</strong> Divide an object into independent parts.</p><p><strong>Application:</strong> Before dispatching in parallel, the system extracts a <strong>dependency graph</strong> based on file paths:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Task A: edit src/auth.ts, src/login.ts</span></span>
<span class="line"><span>Task B: edit src/dashboard.ts, src/chart.ts</span></span>
<span class="line"><span>Task C: edit src/auth.ts, src/api.ts     ← conflicts with Task A!</span></span>
<span class="line"><span></span></span>
<span class="line"><span>→ Batch 1: [A, B] ← run in parallel (no file overlap)</span></span>
<span class="line"><span>→ Batch 2: [C]    ← run strictly after (depends on src/auth.ts)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p><strong>Result:</strong> Only TRULY independent tasks run simultaneously. Eliminates 100% of merge conflicts before they happen.</p><hr><h3 id="_3-—-local-quality" tabindex="-1">#3 — Local Quality <a class="header-anchor" href="#_3-—-local-quality" aria-label="Permalink to &quot;#3 — Local Quality&quot;">​</a></h3><p><strong>Principle:</strong> Each part of a system should fulfill its function in conditions most suitable for its operation.</p><p><strong>Application:</strong> Every agent runs a <strong>mini quality gate</strong> on ITS OWN modified files before reporting completion:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent A completes work:</span></span>
<span class="line"><span>  ✅ Syntax validation: src/auth.ts, src/login.ts → pass</span></span>
<span class="line"><span>  ✅ Tests: 3 passed, 0 failed</span></span>
<span class="line"><span>  ✅ Self-review: no issues</span></span>
<span class="line"><span>  → Report: DONE ✅</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Agent B completes work:</span></span>
<span class="line"><span>  ✅ Syntax validation: src/dashboard.ts → pass  </span></span>
<span class="line"><span>  ❌ Tests: 2 passed, 1 failed          ← ERROR!</span></span>
<span class="line"><span>  → Report: BLOCKED ❌ → must self-correct before continuing</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p><strong>Result:</strong> Bugs are caught AT THE SOURCE by the agent that wrote them, rather than batching them up for a human reviewer at the end.</p><hr><h3 id="_10-—-prior-action" tabindex="-1">#10 — Prior Action <a class="header-anchor" href="#_10-—-prior-action" aria-label="Permalink to &quot;#10 — Prior Action&quot;">​</a></h3><p><strong>Principle:</strong> Perform required changes of an object directly in advance.</p><p><strong>Application:</strong> A <strong>pre-flight check</strong> runs before every batch — scanning the conflict ledger to ensure no overlapping files are currently being modified by running agents:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Before dispatching Batch 2:</span></span>
<span class="line"><span>  → Read conflict ledger</span></span>
<span class="line"><span>  → Is an agent from Batch 1 touching src/auth.ts?</span></span>
<span class="line"><span>    → YES → HALT Batch 2 (Task C targets src/auth.ts)</span></span>
<span class="line"><span>    → NO → Safe to Dispatch ✅</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><strong>Result:</strong> Prevents runtime state corruption proactively.</p><hr><h3 id="_15-—-dynamicity" tabindex="-1">#15 — Dynamicity <a class="header-anchor" href="#_15-—-dynamicity" aria-label="Permalink to &quot;#15 — Dynamicity&quot;">​</a></h3><p><strong>Principle:</strong> Allow characteristics of an object to change to be optimal at each stage.</p><p><strong>Application:</strong> <strong>Adaptive batch sizing</strong> — the system learns during the session:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Session 1: batch_size=2, 0 conflicts → log ✅</span></span>
<span class="line"><span>Session 2: batch_size=2, 0 conflicts → log ✅  </span></span>
<span class="line"><span>Session 3: batch_size=2, 0 conflicts → log ✅</span></span>
<span class="line"><span>Session 4: batch_size=3 ← AUTO-SCALES UP (3 clean runs)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Session 7: batch_size=3, 1 conflict! → log ❌</span></span>
<span class="line"><span>Session 8: batch_size=2 ← AUTO-SCALES DOWN (risk detected)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p><strong>Limits:</strong> Min = 1 (sequential fallback), Max = 5 (hard limit for resource safety).</p><p><strong>Result:</strong> The system adjusts velocity based on empirical history, not guesswork.</p><hr><h3 id="_18-—-feedback-mechanical-vibration" tabindex="-1">#18 — Feedback (Mechanical Vibration) <a class="header-anchor" href="#_18-—-feedback-mechanical-vibration" aria-label="Permalink to &quot;#18 — Feedback (Mechanical Vibration)&quot;">​</a></h3><p><strong>Principle:</strong> If an action is already being performed, introduce periodic pauses or feedback.</p><p><strong>Application:</strong> <strong>Conflict Ledger</strong> — a real-time registry of modified files:</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;sessionId&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;batch-0&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;entries&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;task-a&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;src/auth.ts&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;src/login.ts&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;task-b&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;src/dashboard.ts&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;conflicts&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: []</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>When an agent completes, it <strong>reports ACTUAL files modified</strong> (not just expected). The ledger compares instantly — if an overlap is detected, the run <strong>HALTS</strong>.</p><p><strong>Result:</strong> Continuous feedback loop prevents cascading failure.</p><hr><h3 id="_40-—-composite-materials" tabindex="-1">#40 — Composite Materials <a class="header-anchor" href="#_40-—-composite-materials" aria-label="Permalink to &quot;#40 — Composite Materials&quot;">​</a></h3><p><strong>Principle:</strong> Change from uniform to composite properties.</p><p><strong>Application:</strong> Each agent is not just a &quot;coder&quot; — it is a composite of three personas:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╔══════════════════════════════════════╗</span></span>
<span class="line"><span>║         COMPOSITE AGENT              ║</span></span>
<span class="line"><span>║                                      ║</span></span>
<span class="line"><span>║  👷 Implementer  → Writes code       ║</span></span>
<span class="line"><span>║  🧪 Tester       → Writes/Runs tests ║</span></span>
<span class="line"><span>║  🔍 Reviewer     → Self-reviews      ║</span></span>
<span class="line"><span>║                                      ║</span></span>
<span class="line"><span>║  Reports DONE only if all 3 pass!    ║</span></span>
<span class="line"><span>╚══════════════════════════════════════╝</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p><strong>Result:</strong> No more agents that &quot;finish coding but don&#39;t test.&quot; Quality is baked into the prompt contract.</p><hr><h2 id="the-8-step-lifecycle" tabindex="-1">The 8-Step Lifecycle <a class="header-anchor" href="#the-8-step-lifecycle" aria-label="Permalink to &quot;The 8-Step Lifecycle&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. ANALYZE    → Extract file dependencies from task descriptions using regex</span></span>
<span class="line"><span>2. GRAPH      → Build dependency graph, grouping into independent batches</span></span>
<span class="line"><span>3. ADAPT      → Read history, compute optimal empirical batch size</span></span>
<span class="line"><span>4. PRE-FLIGHT → Check ledger against running agents before dispatch</span></span>
<span class="line"><span>5. DISPATCH   → Send to agents with strict Quality Contracts</span></span>
<span class="line"><span>6. MONITOR    → Agents report actual files → real-time conflict detection</span></span>
<span class="line"><span>7. VERIFY     → Agents run mini-gate (syntax+tests) before reporting</span></span>
<span class="line"><span>8. RECORD     → Save session metrics for future adaptive sizing</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h2 id="troubleshooting-error-handling" tabindex="-1">Troubleshooting &amp; Error Handling <a class="header-anchor" href="#troubleshooting-error-handling" aria-label="Permalink to &quot;Troubleshooting &amp; Error Handling&quot;">​</a></h2><p>When working with parallel execution, conflicts or errors can occur. The system fails safe (drops to sequential) rather than failing fast, but user intervention is sometimes needed.</p><h3 id="💻-using-the-cli" tabindex="-1">💻 Using the CLI <a class="header-anchor" href="#💻-using-the-cli" aria-label="Permalink to &quot;💻 Using the CLI&quot;">​</a></h3><p><strong>1. Conflict Halt Detected</strong></p><ul><li><strong>Symptom:</strong> The console outputs <code>[ERROR] Parallel dispatch halted due to file conflict:</code> followed by the overlapping files and agent IDs.</li><li><strong>Action:</strong><ul><li>The offending tasks are automatically marked as <code>failed</code>.</li><li>Fix the affected files (or review the agent&#39;s work).</li><li>Re-run the task suite sequentially or clean the conflict ledger via <code>node dist/cli.js --clear-ledger</code> to reset the parallel session states safely.</li></ul></li></ul><p><strong>2. Tests Failed by an Agent</strong></p><ul><li><strong>Symptom:</strong> You see <code>[WARNING] Agent X failed local quality gate (Tests: 2 failed)</code>. Check <code>.cm/agent-tasks/&lt;taskId&gt;_report.json</code> for details.</li><li><strong>Action:</strong> Open the respective files the agent touched and correct the failing logic. Since the agent <em>aborted</em>, the <code>task</code> will need to be re-dispatched.</li></ul><p><strong>3. Resetting Adaptive Batching</strong></p><ul><li><strong>Symptom:</strong> The system is only dispatching 1 task at a time (sequential execution) because it encountered multiple conflicts previously.</li><li><strong>Action:</strong> If you are confident the new tasks are clean, you can clear the parallel history to reset the batch size: <code>rm .cm/parallel-history.json</code>.</li></ul><h3 id="🖥️-using-the-ide-extension-vs-code-cursor-integration" tabindex="-1">🖥️ Using the IDE Extension (VS Code / Cursor Integration) <a class="header-anchor" href="#🖥️-using-the-ide-extension-vs-code-cursor-integration" aria-label="Permalink to &quot;🖥️ Using the IDE Extension (VS Code / Cursor Integration)&quot;">​</a></h3><p><strong>1. &quot;Parallel Pre-flight Failed&quot; Notification</strong></p><ul><li><strong>What it means:</strong> You tried to dispatch a batch of tasks from the IDE panel, but the system detected that a currently running background agent is touching a file required by one of your new tasks.</li><li><strong>How to fix:</strong><ol><li>Wait for the active agent to finish processing.</li><li>Click <strong>Refresh Ledger</strong> (or run the equivalent command) in your IDE.</li><li>Dispatch the task again.</li></ol></li></ul><p><strong>2. Agent Blocked by Quality Gate</strong></p><ul><li><strong>What it means:</strong> An agent has completed the code but failed its internal mini-gate validation (syntax or tests). The IDE will flag this task with a ⚠️ Warning icon in the Kanban board.</li><li><strong>How to fix:</strong><ol><li>Hover over the task or click <strong>View Logs</strong> to see the raw output from the quality gate.</li><li>Jump to the modified file directly from the IDE interface (<code>Cmd+Click</code> the filepath).</li><li>Fix the reported bug manually or ask the IDE&#39;s assistant to correct the issue within that context, then mark the task as <code>Done</code>.</li></ol></li></ul><p><strong>3. Debugging File Overlaps</strong></p><ul><li><strong>What it means:</strong> 2 agents actually modified the same file during a run and the real-time feedback loop caught it.</li><li><strong>How to fix:</strong> The IDE will highlight the conflicting file in your Source Control (Git) tab. Review the uncommitted working tree changes closely before committing, as overlapping code merges might exist. The system automatically dropped the batch size for the next run.</li></ul><hr><h2 id="rollback-safety-mechanisms" tabindex="-1">Rollback &amp; Safety Mechanisms <a class="header-anchor" href="#rollback-safety-mechanisms" aria-label="Permalink to &quot;Rollback &amp; Safety Mechanisms&quot;">​</a></h2><h3 id="tier-1-prevention" tabindex="-1">Tier 1: Prevention <a class="header-anchor" href="#tier-1-prevention" aria-label="Permalink to &quot;Tier 1: Prevention&quot;">​</a></h3><ul><li>Dependency parsing actively separates overlapping files from running simultaneously.</li><li>Pre-flight checks ensure batches don&#39;t overlap with currently running agents.</li></ul><h3 id="tier-2-early-detection" tabindex="-1">Tier 2: Early Detection <a class="header-anchor" href="#tier-2-early-detection" aria-label="Permalink to &quot;Tier 2: Early Detection&quot;">​</a></h3><ul><li>Real-time conflict ledger tracks exact files being accessed and catches unpredicted modifications.</li><li>Local Quality gate forces agents to run static analysis before confirming.</li></ul><h3 id="tier-3-self-healing" tabindex="-1">Tier 3: Self-Healing <a class="header-anchor" href="#tier-3-self-healing" aria-label="Permalink to &quot;Tier 3: Self-Healing&quot;">​</a></h3><ul><li>Adaptive batch sizing automatically throttles down the concurrency of agents if errors/conflicts are detected, dropping down to a safe sequential execution fallback (<code>size = 1</code>).</li></ul><h3 id="tier-4-explicit-rollback" tabindex="-1">Tier 4: Explicit Rollback <a class="header-anchor" href="#tier-4-explicit-rollback" aria-label="Permalink to &quot;Tier 4: Explicit Rollback&quot;">​</a></h3><ul><li>Each agent operates in its own sandboxed context. If a conflict halt is triggered, subsequent tasks are aborted to prevent cascading code corruption, and the commit is never pushed.</li></ul>`,74)])])}const g=e(i,[["render",l]]);export{u as __pageData,g as default};
